import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import {
  doc,
  getDoc,
  collection,
  addDoc,
  query,
  orderBy,
  onSnapshot,
} from 'firebase/firestore';
import { db } from '../utils/firebase';

export default function PollResults() {
  const { id } = useParams();
  const [responses, setResponses] = useState([]);
  const [summary, setSummary] = useState({});
  const [pollName, setPollName] = useState('');
  const [bestDates, setBestDates] = useState([]);
  const [message, setMessage] = useState('');
  const [copied, setCopied] = useState(false);
  const [comments, setComments] = useState([]);
  const [userName, setUserName] = useState('');
  const [participantCount, setParticipantCount] = useState(0);

  useEffect(() => {
    const fetchPollData = async () => {
      const ref = doc(db, 'polls', id);
      const snap = await getDoc(ref);
      if (snap.exists()) {
        const data = snap.data();
        setPollName(data.name);
        const all = data.responses || [];
        setResponses(all);
        setParticipantCount(all.length);

        const summaryMap = {};
        all.forEach((resp) => {
          (resp.availability || []).forEach(({ date, times }) => {
            if (!summaryMap[date]) {
              summaryMap[date] = { Morning: [], Afternoon: [], Evening: [] };
            }
            times.forEach((slot) => {
              summaryMap[date][slot].push(resp.name);
            });
          });
        });

        const sortedSummary = Object.entries(summaryMap).sort(
          ([a], [b]) => new Date(a) - new Date(b)
        );
        const sortedSummaryMap = Object.fromEntries(sortedSummary);
        setSummary(sortedSummaryMap);

        const perfectDates = Object.entries(sortedSummaryMap)
          .filter(([_, slots]) =>
            Object.values(slots).some((names) => names.length === all.length)
          )
          .map(([date]) => date);

        setBestDates(perfectDates);
      }
    };

    fetchPollData();
  }, [id]);

  useEffect(() => {
    const commentsRef = collection(db, 'polls', id, 'comments');
    const q = query(commentsRef, orderBy('timestamp', 'asc'));
    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const commentsData = querySnapshot.docs.map((doc) => doc.data());
      setComments(commentsData);
    });
    return () => unsubscribe();
  }, [id]);

  const handleCommentSubmit = async () => {
    if (message.trim() && userName.trim()) {
      try {
        await addDoc(collection(db, 'polls', id, 'comments'), {
          name: userName,
          message,
          timestamp: new Date(),
        });
        setMessage('');
      } catch (err) {
        console.error('Error submitting comment:', err);
      }
    } else {
      alert('Please enter both your name and a message.');
    }
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(window.location.href);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getColorClass = (count) => {
    if (count === 0) return 'bg-red-100';
    if (count === participantCount) return 'bg-green-100';
    return 'bg-yellow-100';
  };

  return (
    <div className="min-h-screen bg-gray-100 p-6 flex flex-col items-center">
      {/* Floating Summary */}
      <div className="w-full max-w-3xl mb-6 bg-white p-4 rounded shadow sticky top-0 z-10">
        <h1 className="text-2xl font-bold mb-2">{pollName}</h1>
        <p>Total Invited: {participantCount}</p>
        <p>Best Dates (everyone available): {bestDates.length > 0 ? bestDates.join(', ') : 'None yet'}</p>
        <button
          onClick={handleCopy}
          className="mt-2 text-sm text-blue-600 hover:text-blue-800 underline"
        >
          {copied ? 'Link copied!' : 'Share this poll'}
        </button>
      </div>

      {/* Table View */}
      <div className="w-full max-w-5xl overflow-x-auto bg-white p-6 rounded-lg shadow-md">
        <h2 className="text-xl font-semibold mb-4">Availability Table</h2>
        <table className="w-full table-auto border-collapse">
          <thead>
            <tr className="bg-gray-200">
              <th className="border p-2 text-left">Date</th>
              <th className="border p-2 text-left">Morning</th>
              <th className="border p-2 text-left">Afternoon</th>
              <th className="border p-2 text-left">Evening</th>
            </tr>
          </thead>
          <tbody>
            {Object.entries(summary).map(([date, slots]) => (
              <tr key={date}>
                <td className="border p-2 font-semibold">{date}</td>
                {['Morning', 'Afternoon', 'Evening'].map((slot) => (
                  <td key={slot} className={`border p-2 ${getColorClass(slots[slot]?.length || 0)}`}>
                    {slots[slot]?.length ? slots[slot].join(', ') : '—'}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Comments Section */}
      <div className="mt-8 w-full max-w-3xl bg-white p-6 rounded-lg shadow-md">
        <h2 className="text-xl font-semibold mb-4">Comments</h2>
        <div className="max-h-64 overflow-y-auto mb-4">
          {comments.map((comment, index) => (
            <div key={index} className="mb-2">
              <p className="font-semibold">{comment.name}</p>
              <p>{comment.message}</p>
            </div>
          ))}
        </div>
        <div className="flex flex-col gap-2">
          <input
            type="text"
            placeholder="Your Name"
            value={userName}
            onChange={(e) => setUserName(e.target.value)}
            className="p-2 border rounded"
          />
          <textarea
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Type a comment..."
            className="p-2 border rounded"
          />
          <button
            onClick={handleCommentSubmit}
            className="mt-2 bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
          >
            Submit Comment
          </button>
        </div>
      </div>
    </div>
  );
}
